mapper.sql:
/* wms-inbound-iborderplcm-sql-oracle.xml - selectIbOrderDtsql - 입고 적치 상세 조회 SQL */ SELECT * FROM ( SELECT '0' AS CHK , A.CTKEY , B.CTNM , A.OWKEY , C.IBHDTYPECD , C.IBEXPCTDATE , A.ICKEY , CASE WHEN C.IBHDTYPECD = '30' THEN C.ACNM ELSE '' END AS OB_CTNM , CASE WHEN C.IBHDTYPECD != '30' THEN C.ACNM ELSE '' END AS ACNM , A.IBHDKEY , A.IBDTKEY , C.REQORDERNO , I.EXTORDERKEY , D.ACKEY AS IC_ACKEY , E.ACNM AS IC_ACNM , CASE WHEN F.ASRTDTICKEY IS NOT NULL AND I.UPRIBDTKEY IS NOT NULL THEN F.ASRTMASICKEY ELSE A.ICKEY END AS ASRTMASICKEY , CASE WHEN F.ASRTDTICKEY IS NOT NULL AND I.UPRIBDTKEY IS NOT NULL THEN G.ICNM ELSE D.ICNM END AS ASRTMASICNM , CASE WHEN F.ASRTDTICKEY IS NOT NULL AND I.UPRIBDTKEY IS NOT NULL THEN A.ICKEY END AS ASRTDTICKEY , CASE WHEN F.ASRTDTICKEY IS NOT NULL AND I.UPRIBDTKEY IS NOT NULL THEN D.ICNM END AS ASRTDTICNM , I.ASRTWKTGTYN AS ASRTYN , CTG3.CTGNM AS LV1_CTGNM , CTG2.CTGNM AS LV2_CTGNM , CTG1.CTGNM AS LV3_CTGNM , I.UOM , A.CNTRNO , COALESCE(A.QTY, 0) AS CNTRQTY , ROUND(A.QTY / NULLIF(COALESCE(J.ICUNITQTY, 0), 0), 2) AS CNTRQTY_INN , ROUND(A.QTY / NULLIF(COALESCE(K.ICUNITQTY, 0), 0), 2) AS CNTRQTY_CTN , ROUND(A.QTY / (NULLIF(COALESCE(K.ICUNITQTY, 0), 0) * NULLIF(COALESCE(K.CPPQTY, 0), 0)), 2) AS CNTRQTY_PLT
, COALESCE(A.CNFRMQTY, 0) AS CNFRMQTY , ROUND(A.CNFRMQTY / NULLIF(COALESCE(J.ICUNITQTY, 0), 0), 2) AS CNFRMQTY_INN , ROUND(A.CNFRMQTY / NULLIF(COALESCE(K.ICUNITQTY, 0), 0), 2) AS CNFRMQTY_CTN , ROUND(A.CNFRMQTY / (NULLIF(COALESCE(K.ICUNITQTY, 0), 0) * NULLIF(COALESCE(K.CPPQTY, 0), 0)), 2) AS CNFRMQTY_PLT
, COALESCE(A.QTY, 0) - COALESCE(A.CNFRMQTY, 0) AS RESQTY , ROUND((COALESCE(A.QTY, 0) - COALESCE(A.CNFRMQTY, 0)) / NULLIF(COALESCE(J.ICUNITQTY, 0), 0), 2) AS RESQTY_INN , ROUND((COALESCE(A.QTY, 0) - COALESCE(A.CNFRMQTY, 0)) / NULLIF(COALESCE(K.ICUNITQTY, 0), 0), 2) AS RESQTY_CTN , ROUND((COALESCE(A.QTY, 0) - COALESCE(A.CNFRMQTY, 0)) / (NULLIF(COALESCE(K.ICUNITQTY, 0), 0) * NULLIF(COALESCE(K.CPPQTY, 0), 0)), 2) AS RESQTY_PLT
, I.UOM AS IN_UOM , L.ICUNITQTY , 0 AS INQTY_UNIT , 0 AS INQTY , A.PRDCTDATE , A.EXPDATE AS ORG_EXPDATE , A.EXPDATE , D.LCKEY AS TOLCKEY , LC.ZNKEY AS TOZNKEY , '' AS TOCNTRNO , D.LCKEY AS REF_LCKEY , D.EXPCKYN , D.EXPCKTYPECD , D.ICGRPKEY , M.PLCMSTATUSCD , A.IBCFSEQNO , A.IVATKEY , CASE WHEN L.WIDTH = 0 OR L.DEPTH = 0 OR L.HEIGHT = 0 OR L.WEIGHT = 0 THEN 'N' WHEN D.ROBSORTERICYN IS NULL OR D.CUSHNMEPCKGYN IS NULL OR D.BARCODEATTACHYN IS NULL OR D.POLYBAGPCKGYN IS NULL OR D.PCKGOVLPYN IS NULL THEN 'N' WHEN D.PCKGOVLPYN = 'Y' AND (D.OVLPPCKGWIDTHVAL = 0 AND D.OVLPPCKGDEPTHVAL = 0 AND D.OVLPPCKGHEIGHTVAL = 0) THEN 'N' WHEN D.PCKGFOLDYN IS NULL OR D.HIGHFRQNCYDMGYN IS NULL THEN 'N' ELSE 'Y' END AS ICYN , CASE WHEN COALESCE(A.QTY, 0) - COALESCE(A.CNFRMQTY, 0) > 0 THEN 'Y' ELSE 'N' END AS NONPLCMYN , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TWORK_INFO_IBCF_CNTR A INNER JOIN TWORK_MST_CT B ON A.CTKEY = B.CTKEY INNER JOIN TWORK_INFO_IB_HD C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.IBHDKEY = C.IBHDKEY INNER JOIN TWORK_MST_IC D ON A.CTKEY = D.CTKEY AND A.OWKEY = D.OWKEY AND A.ICKEY = D.ICKEY LEFT OUTER JOIN TWORK_MST_LC LC ON D.CTKEY = LC.CTKEY AND D.LCKEY = LC.LCKEY LEFT OUTER JOIN TWORK_MST_AC E ON A.CTKEY = E.CTKEY AND D.ACKEY = E.ACKEY LEFT OUTER JOIN TWORK_MST_ASRT F ON A.CTKEY = F.CTKEY AND A.OWKEY = F.OWKEY AND A.ICKEY = F.ASRTDTICKEY LEFT OUTER JOIN TWORK_MST_IC G ON A.CTKEY = G.CTKEY AND A.OWKEY = G.OWKEY AND F.ASRTMASICKEY = G.ICKEY INNER JOIN TWORK_INFO_IB_DT I ON A.CTKEY = I.CTKEY AND A.OWKEY = I.OWKEY AND A.IBHDKEY = I.IBHDKEY AND A.IBDTKEY = I.IBDTKEY LEFT OUTER JOIN TWORK_MST_ICUTXTYPE J ON A.CTKEY = J.CTKEY AND A.OWKEY = J.OWKEY AND D.ICUNITKEY = J.ICUNITKEY AND J.ICUNITTYPECD = 'INN' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE K ON A.CTKEY = K.CTKEY AND A.OWKEY = K.OWKEY AND D.ICUNITKEY = K.ICUNITKEY AND K.ICUNITTYPECD = 'CTN' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE L ON A.CTKEY = L.CTKEY AND A.OWKEY = L.OWKEY AND D.ICUNITKEY = L.ICUNITKEY AND L.ICUNITTYPECD = 'EA' INNER JOIN TWORK_INFO_IBCF_DT M ON A.CTKEY = M.CTKEY AND A.OWKEY = M.OWKEY AND A.IBHDKEY = M.IBHDKEY AND A.IBDTKEY = M.IBDTKEY AND A.IBCFSEQNO = M.IBCFSEQNO INNER JOIN TWORK_MST_ICBARCODE N ON A.CTKEY = N.CTKEY AND A.OWKEY = N.OWKEY AND A.ICKEY = N.ICKEY AND N.UOM = 'EA' INNER JOIN TWORK_MST_CTG CTG1 ON A.CTKEY = CTG1.CTKEY AND A.OWKEY = CTG1.OWKEY AND D.CTGKEY = CTG1.CTGKEY AND CTG1.CTGLV = '3' INNER JOIN TWORK_MST_CTG CTG2 ON CTG1.CTKEY = CTG2.CTKEY AND CTG1.OWKEY = CTG2.OWKEY AND CTG1.UPRCTGKEY = CTG2.CTGKEY AND CTG2.CTGLV = '2' INNER JOIN TWORK_MST_CTG CTG3 ON CTG2.CTKEY = CTG3.CTKEY AND CTG2.OWKEY = CTG3.OWKEY AND CTG2.UPRCTGKEY = CTG3.CTGKEY AND CTG3.CTGLV = '1' WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND A.IBHDKEY = #{ibhdkey} AND A.QTY > 0
#{ickey}
AND D.ICNM LIKE '%'|| #{icnm} || '%'
AND N.BARCODE = #{barcode}
) A WHERE 1=1

mapper.select:
/* wms-inbound-iborderplcm-sql-oracle.xml - selectIbOrderPlcmDtByPrdctAndExpdate - 적치 테이블 조회  */
SELECT *
  FROM TWORK_INFO_IB_PLCM_DT
 WHERE CTKEY   = #{ctkey}
   AND OWKEY   = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}
   AND LCKEY   = #{lckey}
   AND IBCFCNTRNO = #{ibcfcntrno}
   AND CNTRNO  = #{cntrno}
   AND IBCFSEQNO = #{ibcfseqno}
   AND (EXPDATE = #{expdate} OR (EXPDATE IS NULL AND #{expdate} IS NULL))
   AND (PRDCTDATE = #{prdctdate} OR (PRDCTDATE IS NULL AND #{prdctdate} IS NULL))

