mapper.update:
/* wms-inbound-iborderplcm-sql-oracle.xml - updatePlcmDt - 적치 수량 수정 */
UPDATE TWORK_INFO_IB_PLCM_DT
   SET CNFRMQTY 	= CNFRMQTY 	+ #{cnfrmqty}
	 , UPDATEDATE 	= #{sysdate}
	 , UPDATEURKEY 	= #{surkey}
 WHERE CTKEY   		= #{ctkey}
   AND OWKEY   		= #{owkey}
   AND IBHDKEY 		= #{ibhdkey}
   AND IBDTKEY 		= #{ibdtkey}
   AND IBCFSEQNO	= #{ibcfseqno}
   AND SEQNO 		= #{seqno}

mapper.select:
/* wms-inbound-iborderplcm-sql-oracle.xml - selectIbPlcmDtSeqno - 입고 적치 시리얼 번호 조회 */
SELECT COALESCE(MAX(SEQNO) + 1, 1)
  FROM TWORK_INFO_IB_PLCM_DT
 WHERE CTKEY   = #{ctkey}
   AND OWKEY   = #{owkey}
   AND IBHDKEY = #{ibhdkey}

mapper.update:
/* wms-inbound-iborderplcm-sql-oracle.xml - updateIbcfDtCnfrmqty - 입고 확정 상세 적치수량 저장 */
UPDATE TWORK_INFO_IBCF_DT
   SET CNFRMQTY = CNFRMQTY + #{cnfrmqty}
	 , PLCMSTATUSCD = (
						CASE WHEN IBQTY = CNFRMQTY + #{cnfrmqty} THEN '20'
							 WHEN CNFRMQTY + #{cnfrmqty} = 0 THEN '00'
							 ELSE '10' END
					   )
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY   = #{ctkey}
   AND OWKEY   = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}
   AND IBCFSEQNO = #{ibcfseqno}

/* wms-inbound-iborderplcm-sql-oracle.xml - updateAsrtMasIbcfDtCnfrmqty - 입고 확정 상세 모상품 적치수량 저장 */
UPDATE TWORK_INFO_IBCF_DT
   SET CNFRMQTY = CNFRMQTY + #{cnfrmqty}
	 , PLCMSTATUSCD = (
						CASE WHEN IBQTY = CNFRMQTY + #{cnfrmqty} THEN '20'
							 WHEN CNFRMQTY + #{cnfrmqty} = 0 THEN '00'
							 ELSE '10' END
					   )
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY   = #{ctkey}
   AND OWKEY   = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{upribdtkey}

/* wms-inbound-iborderplcm-sql-oracle.xml - updateIbcfCntrCnfrmqty - 용기 확정 상세 적치수량 저장 */
UPDATE TWORK_INFO_IBCF_CNTR
   SET CNFRMQTY = CNFRMQTY + #{cnfrmqty}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY   = #{ctkey}
   AND OWKEY   = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}
   AND IBCFSEQNO = #{ibcfseqno}
   AND CNTRNO = #{cntrno}

/* wms-inbound-iborderplcm-sql-oracle.xml - updateIbcfCntrQty - 용기 확정 상세 입고수량 저장 */
UPDATE TWORK_INFO_IBCF_CNTR
   SET QTY = QTY + #{qty}
     , UPDATEDATE = #{sysdate}
     , UPDATEURKEY = #{surkey}
 WHERE CTKEY   = #{ctkey}
   AND OWKEY   = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}
   AND CNTRNO = #{cntrno}

