mapper.update:
/* wms-inbound-iborderplcm-sql-oracle.xml - updateIbDtCnfrmqty - 입고 상세 적치수량 저장 */
UPDATE TWORK_INFO_IB_DT
   SET CNFRMQTY = CNFRMQTY + #{cnfrmqty}
	 , PLCMSTATUSCD = (
						CASE WHEN EXPCTQTY = CNFRMQTY + #{cnfrmqty} THEN '20'
							 WHEN CNFRMQTY + #{cnfrmqty} = 0 THEN '00'
						ELSE '10' END
						)
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY   = #{ctkey}
   AND OWKEY   = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}

/* wms-inbound-iborderplcm-sql-oracle.xml - updateAsrtMasIbDtCnfrmqty - 아소트 모상품 입고 상세 적치수량 저장 */
UPDATE TWORK_INFO_IB_DT
   SET CNFRMQTY = CNFRMQTY + #{cnfrmqty}
	 , PLCMSTATUSCD = (
						CASE WHEN EXPCTQTY = CNFRMQTY + #{cnfrmqty} THEN '20'
							 WHEN CNFRMQTY + #{cnfrmqty} = 0 THEN '00'
							 ELSE '10' END
					  )
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY   = #{ctkey}
   AND OWKEY   = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{upribdtkey}

mapper.delete:
