   AND IBHDKEY 	 = #{ibhdkey}
   AND IBDTKEY   = #{ibdtkey}
   AND IBCFSEQNO = #{ibcfseqno}
   AND SEQNO 	 = #{seqno}

mapper.select:
/* wms-inbound-iborderplcm-sql-oracle.xml - selectIbPlcmDt - 적치 삭제 */
SELECT *
  FROM TWORK_INFO_IB_PLCM_DT
 WHERE CTKEY 	 = #{ctkey}
   AND OWKEY 	 = #{owkey}
   AND IBHDKEY 	 = #{ibhdkey}
   AND IBDTKEY   = #{ibdtkey}
   AND IBCFSEQNO = #{ibcfseqno}
   AND SEQNO 	 = #{seqno}
